import{c as t,Q as o,j as i,m as a}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"ADR-023 — Porkchop plot mobile interaction (RFC-006 Option C)","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-023.md","filePath":"adr/ADR-023.md"}'),n={name:"adr/ADR-023.md"};function s(r,e,l,c,h,p){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-023-—-porkchop-plot-mobile-interaction-rfc-006-option-c" tabindex="-1">ADR-023 — Porkchop plot mobile interaction (RFC-006 Option C) <a class="header-anchor" href="#adr-023-—-porkchop-plot-mobile-interaction-rfc-006-option-c" aria-label="Permalink to &quot;ADR-023 — Porkchop plot mobile interaction (RFC-006 Option C)&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-28 Closes · RFC-006 (Porkchop plot mobile interaction) TA anchor · §components/porkchop-plot · §contracts/porkchop-mobile</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The porkchop plot on <code>/plan</code> is dense — 112 × 100 = 11,200 cells in a viewport that, on a 375 × 812 phone, gives each cell roughly 2.8 × 4.5 CSS pixels. Direct tap selection is impossible: thumbs land on a 5–7 cell region and the user can&#39;t tell which one was picked.</p><p>RFC-006 enumerated three options:</p><ul><li><strong>Option A</strong> — pan/zoom with native pinch gestures.</li><li><strong>Option B</strong> — strip the colour overview, replace with a simpler date picker.</li><li><strong>Option C</strong> — full plot visible; touch-and-hold opens a magnifier bubble showing 5×5 cells at large scale; slide to navigate; lift to select.</li></ul><p>PRD-002&#39;s educational core is the colour pattern itself (&quot;see the launch windows opening&quot;), so any option that hides that pattern (Option B) is a non-starter. Option A is richer but adds zoom/pan complexity (gesture conflicts with the underlying scroll, momentum, viewport math).</p><p>Closure was scheduled for the Slice 3 gate after device validation. We close it here in 3a-8 alongside the implementation; validation is via the Playwright e2e suite (<code>tests/e2e/plan.spec.ts</code>) running against a Pixel 5 mobile-Chromium device profile that exercises the touch-tap → magnifier → cell-select flow on every push to main. Real-iOS / real-Android user testing is deferred to the Slice 6 polish gate when WCAG 2.1 AA work also lands.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Option C — magnifier bubble.</strong> Touch and hold anywhere in the plot opens a 140 × 140 px circular magnifier showing a 5 × 5 cell window centred on the touch point. Sliding the finger updates which cells are shown and which is at the centre crosshair. Lifting selects the centre cell. The Δv value of the centre cell is rendered inside the bubble for confirmation before lift.</p><p>Desktop interaction is unchanged: hover highlights, click selects.</p><p>Implementation lives in <code>src/routes/plan/+page.svelte</code> (commit <a href="https://github.com/chipi/orrery/commit/12e5359" target="_blank" rel="noreferrer"><code>12e5359</code></a>) — about 50 lines of touch event handling, a separate magnifier <code>&lt;canvas&gt;</code> overlay, and a <code>drawMag()</code> helper that reads from the same in-memory grid as the main heatmap.</p><h3 id="answers-to-rfc-006-open-questions" tabindex="-1">Answers to RFC-006 open questions <a class="header-anchor" href="#answers-to-rfc-006-open-questions" aria-label="Permalink to &quot;Answers to RFC-006 open questions&quot;">​</a></h3><ol><li><strong>Should the magnifier show Δv values numerically inside each enlarged cell?</strong> No — the centre cell&#39;s Δv is shown at the bottom of the bubble (the only cell that matters at lift time). Rendering 25 small text labels inside the bubble would clutter the colour pattern.</li><li><strong>What happens when the user lifts their finger outside the plot area — cancel or select nearest cell?</strong> Selects whichever cell the magnifier was centred on at lift. The magnifier itself is constrained to the plot area (<code>cellFromCanvas</code> returns null outside), so dragging off the plot hides the magnifier; lifting in that state is a no-op (touch end with <code>mag === null</code> doesn&#39;t change selection).</li><li><strong>Should there be a &quot;best window&quot; auto-suggest button?</strong> Deferred. The full overview already makes the cheap blue zones visually obvious; an auto-suggest button would short-circuit the educational moment. v2 candidate if usability testing shows users skipping the colour pattern entirely.</li></ol><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Option C preserves the educational colour overview that is PRD-002&#39;s core claim. The magnifier is a familiar mobile pattern (iOS text selection, Notes app annotations) so users hit it without onboarding. Touch-action: <code>none</code> on the canvas prevents native scroll/zoom from conflicting with the gesture.</p><p>The 5 × 5 region is a balance: fewer cells (3 × 3) makes the magnifier feel imprecise; more (7 × 7) shrinks each enlarged cell back below the thumb&#39;s hit-test pad and defeats the purpose. 5 × 5 with a 140 px bubble gives each enlarged cell ~28 px on a side — comfortable thumb selection.</p><p>The magnifier offsets above the touch point by 90 px so the user&#39;s finger doesn&#39;t occlude the cells they&#39;re navigating.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Option A (pinch-to-zoom).</strong> Richer but introduces gesture conflicts and viewport-coordinate complexity. Strong v2 candidate once the mobile baseline is established.</li><li><strong>Option B (strip the heatmap, pure date picker).</strong> Loses the educational core. Rejected.</li><li><strong>Tap-only with hit-pad expansion.</strong> Tested informally: even with 16 px hit-pad per cell, target overlap is ambiguous in the dense low-Δv basin where every adjacent cell is also viable. Doesn&#39;t actually solve the precision problem.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: full porkchop pattern visible at native resolution on mobile; precise selection via familiar pattern; no gesture conflicts; same code path as desktop for everything except the magnifier overlay.</p><p>Negative: no current way to pan a non-existent zoomed-in view (intentionally — Option A is the v2 answer if pan/zoom becomes desirable). Magnifier consumes the second touch for two-finger gestures; touchstart guards on <code>e.touches.length !== 1</code> so a pinch attempt is a no-op rather than a conflicting selection.</p>',23)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
